  3→interface RegisteredCommand extends CommandDef {
  4→  /** Scope extracted from pluginName, e.g. '@openacp/speech' → 'speech' */
  5→  scope?: string
  6→}
  7→
  8→/**
  9→ * Central command registry with namespace resolution and adapter-specific overrides.
 10→ *
 11→ * Namespace rules:
 12→ * - System commands always own the short name.
 13→ * - Among plugins, the first to register wins the short name.
 14→ * - Every plugin command also gets a qualified name: `scope:name`.
 15→ * - Adapter plugins (@openacp/telegram, @openacp/discord, @openacp/slack)
 16→ *   registering a command that already exists → stored as an override
 17→ *   keyed by `channelId:commandName`, used when channelId matches.
 18→ */
 19→export class CommandRegistry {
 20→  /** Main registry: short names + qualified names → RegisteredCommand */
 21→  private commands = new Map<string, RegisteredCommand>()
 22→
 23→  /** Adapter-specific overrides: `channelId:commandName` → RegisteredCommand */
 24→  private overrides = new Map<string, RegisteredCommand>()
 25→
 26→  private static ADAPTER_SCOPES = new Set(['telegram', 'discord', 'slack'])
 27→
 28→  /**
 29→   * Register a command definition.
 30→   * @param def - Command definition
 31→   * @param pluginName - Plugin that owns the command (set automatically by PluginContext)
 32→   */
 33→  register(def: CommandDef, pluginName?: string): void {
 34→    const cmd: RegisteredCommand = {
 35→      ...def,
 36→      pluginName: pluginName ?? def.pluginName,
 37→    }
 38→
 39→    if (pluginName) {
 40→      cmd.scope = CommandRegistry.extractScope(pluginName)
 41→    }
 42→
 43→    const qualifiedName = cmd.scope ? `${cmd.scope}:${cmd.name}` : undefined
 44→
 45→    // Check if this is an adapter plugin overriding an existing command
 46→    if (cmd.scope && CommandRegistry.ADAPTER_SCOPES.has(cmd.scope) && this.commands.has(cmd.name)) {
 47→      // Store as adapter override
 48→      this.overrides.set(`${cmd.scope}:${cmd.name}`, cmd)
 49→      return
 50→    }
 51→
 52→    // Always register qualified name if available
 53→    if (qualifiedName) {
 54→      this.commands.set(qualifiedName, cmd)
 55→    }
 56→
 57→    // Short name logic
 58→    if (this.commands.has(cmd.name)) {
 59→      const existing = this.commands.get(cmd.name)!
 60→      // System commands always win the short name
 61→      if (existing.category === 'system') {
 62→        // Plugin gets qualified name only (already registered above)
 63→        return
 64→      }
 65→      // First plugin wins short name; later plugins get qualified only
 66→      return
 67→    }
 68→
 69→    // No conflict — register short name
 70→    this.commands.set(cmd.name, cmd)
 71→  }
 72→
 73→  /** Retrieve a command by name (short or qualified). */
 74→  get(name: string): RegisteredCommand | undefined {
 75→    return this.commands.get(name)
 76→  }
 77→
 78→  /** Remove a command by short name. Also removes its qualified name entry. */
 79→  unregister(name: string): void {
 80→    const cmd = this.commands.get(name)
 81→    if (cmd) {
 82→      this.commands.delete(name)
 83→      // Also remove qualified name
 84→      if (cmd.scope) {
 85→        this.commands.delete(`${cmd.scope}:${name}`)
 86→      }
 87→    }
 88→    // Also try removing as qualified name
 89→    if (!cmd) {
 90→      this.commands.delete(name)
 91→    }
 92→  }
 93→
 94→  /** Remove all commands registered by a given plugin. */
 95→  unregisterByPlugin(pluginName: string): void {
 96→    const scope = CommandRegistry.extractScope(pluginName)
 97→    const toDelete: string[] = []
 98→
 99→    for (const [key, cmd] of this.commands) {
100→      if (cmd.pluginName === pluginName) {
101→        toDelete.push(key)
102→      }
103→    }
104→
105→    for (const key of toDelete) {
106→      this.commands.delete(key)
107→    }
108→
109→    // Also remove adapter overrides
110→    for (const [key, cmd] of this.overrides) {
111→      if (cmd.pluginName === pluginName) {
112→        this.overrides.delete(key)
113→      }
114→    }
115→  }
116→
117→  /** Return all unique commands (deduplicated — each command appears once). */
118→  getAll(): RegisteredCommand[] {
119→    const seen = new Set<RegisteredCommand>()
120→    for (const cmd of this.commands.values()) {
121→      seen.add(cmd)
122→    }
123→    return [...seen]
124→  }
125→
126→  /** Filter commands by category. */
127→  getByCategory(category: 'system' | 'plugin'): RegisteredCommand[] {
128→    return this.getAll().filter((cmd) => cmd.category === category)
129→  }
130→
131→  /**
132→   * Parse and execute a command string.
133→   * @param commandString - Full command string, e.g. "/greet hello world"
134→   * @param baseArgs - Base arguments (channelId, userId, etc.)
135→   * @returns CommandResponse
136→   */
137→  async execute(commandString: string, baseArgs: CommandArgs): Promise<CommandResponse> {
138→    // Parse command name and raw args
139→    const trimmed = commandString.trim()
140→    const spaceIdx = trimmed.indexOf(' ')
141→    const rawCmd = spaceIdx === -1 ? trimmed.slice(1) : trimmed.slice(1, spaceIdx)
142→    const cmdName = rawCmd.split("@")[0]
143→    const rawArgs = spaceIdx === -1 ? '' : trimmed.slice(spaceIdx + 1)
144→
145→    // Check for adapter-specific override first
146→    const overrideKey = `${baseArgs.channelId}:${cmdName}`
147→    const override = this.overrides.get(overrideKey)
148→
149→    const cmd = override ?? this.commands.get(cmdName)
150→
151→    if (!cmd) {
152→      return { type: 'error', message: `Unknown command: /${cmdName}` }
153→    }
154→
155→    const args: CommandArgs = {
156→      ...baseArgs,
157→      raw: rawArgs,
158→    }
159→
160→    try {
161→      const result = await cmd.handler(args)
162→      if (result === undefined || result === null) {
163→        return { type: 'silent' }
164→      }
165→      return result
166→    } catch (err) {
167→      const message = err instanceof Error ? err.message : String(err)
168→      return { type: 'error', message: `Command /${cmdName} failed: ${message}` }
169→    }
170→  }
171→
172→  /** Extract scope from plugin name: '@openacp/speech' → 'speech', 'my-plugin' → 'my-plugin' */
173→  static extractScope(pluginName: string): string {
174→    const slashIdx = pluginName.lastIndexOf('/')
175→    if (slashIdx !== -1) {
176→      return pluginName.slice(slashIdx + 1)
177→    }
178→    return pluginName
179→  }
180→}
