  it("high shows progress bar + cost", () => {
    const result = formatUsage(
      { tokensUsed: 28000, contextSize: 200000, cost: 0.25 },
      "high",
    );
    expect(result).toContain("▓");
    expect(result).toContain("💰 $0.25");
  });
});

